# -*- coding: utf-8 -*-
"""
i18n.py - ソフト全体のUI表示言語（12言語）切り替え

_CURRENT_THEME と同じ設計（グローバル変数 + 切替関数）。
未収録の文字列は原文をそのまま返すので、翻訳漏れがあってもクラッシュしない。
"""

_CURRENT_LANG = "ja"

_SUPPORTED_LANGS = ("ja", "en", "es", "pt", "de", "fr", "id", "hi", "ko", "it", "tr", "nl")


def set_lang(lang: str):
    global _CURRENT_LANG
    _CURRENT_LANG = lang if lang in _SUPPORTED_LANGS else "ja"


def get_lang() -> str:
    return _CURRENT_LANG


def T(text: str) -> str:
    """UI文字列を現在の表示言語に翻訳する。日本語のまま・未収録なら原文を返す"""
    if _CURRENT_LANG == "ja":
        return text
    return _STRINGS.get(_CURRENT_LANG, {}).get(text, text)


